import { useRef, useEffect, useMemo, Suspense, forwardRef, useState } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Stars, Line, Html } from '@react-three/drei';
import { EffectComposer, Bloom } from '@react-three/postprocessing';
import * as THREE from 'three';
import { AnimalTrack, TrackingPoint } from '../../types/movebank';

interface GlobeProps {
  animalTracks: AnimalTrack[];
  selectedAnimal: string | null;
  onAnimalSelect: (animalId: string) => void;
  playbackProgress: number;
}

function latLngToVector3(lat: number, lng: number, radius: number = 1.01): THREE.Vector3 {
  const phi = (90 - lat) * (Math.PI / 180);
  const theta = (lng + 180) * (Math.PI / 180);

  return new THREE.Vector3(
    -radius * Math.sin(phi) * Math.cos(theta),
    radius * Math.cos(phi),
    radius * Math.sin(phi) * Math.sin(theta)
  );
}

function AnimalPath({ track, progress, onAnimalSelect, isSelected }: { 
  track: AnimalTrack; 
  progress: number; 
  onAnimalSelect?: (animalId: string) => void;
  isSelected?: boolean;
}) {
  const [isHovered, setIsHovered] = useState(false);
  const points = useMemo(() => {
    const visibleCount = Math.floor(track.points.length * progress);
    return track.points.slice(0, Math.max(visibleCount, 1)).map(p =>
      latLngToVector3(p.lat, p.lng)
    );
  }, [track.points, progress]);

  const lastPoint = track.points[Math.floor(track.points.length * progress) - 1];
  
  return (
    <group>
      {points.length > 1 && (
        <Line
          points={points}
          color={track.color}
          lineWidth={isSelected ? 12 : 8}
          transparent
          opacity={isSelected ? 1 : 0.8}
        />
      )}
      {points.length > 0 && lastPoint && (
        <mesh
          position={points[points.length - 1]}
          onPointerOver={(e) => { e.stopPropagation(); setIsHovered(true); }}
          onPointerOut={(e) => { e.stopPropagation(); setIsHovered(false); }}
          onClick={(e) => { e.stopPropagation(); if (onAnimalSelect) onAnimalSelect(track.animalId); }}
        >
          <sphereGeometry args={[isSelected ? 0.08 : (isHovered ? 0.06 : 0.05), 16, 16]} />
          <meshStandardMaterial
            color={track.color}
            emissive={track.color}
            emissiveIntensity={isSelected ? 8 : (isHovered ? 5 : 3)}
          />
          {isSelected && (
            <mesh rotation={[Math.PI / 2, 0, 0]}>
              <torusGeometry args={[0.1, 0.01, 16, 32]} />
              <meshBasicMaterial color={track.color} transparent opacity={0.6} />
            </mesh>
          )}
          {isHovered && (
            <Html
              position={[0, 0.1, 0]}
              center
              distanceFactor={10}
              style={{ pointerEvents: 'none' }}
            >
              <div style={{
                background: 'rgba(0,0,0,0.8)',
                color: 'white',
                padding: '8px 12px',
                borderRadius: '8px',
                fontSize: '12px',
                whiteSpace: 'nowrap',
                border: `1px solid ${track.color}`,
                backdropFilter: 'blur(4px)',
              }}>
                <div style={{ fontWeight: 'bold', marginBottom: '4px' }}>{track.animalName}</div>
                {lastPoint.timestamp && (
                  <div>{new Date(lastPoint.timestamp).toLocaleString()}</div>
                )}
                <div>Lat: {lastPoint.lat.toFixed(4)}, Lng: {lastPoint.lng.toFixed(4)}</div>
              </div>
            </Html>
          )}
        </mesh>
      )}
    </group>
  );
}

function Earth() {
  const earthTexture = useMemo(() => {
    const loader = new THREE.TextureLoader();
    const texture = loader.load('/textures/earth-blue-marble.jpg');
    texture.anisotropy = 16;
    return texture;
  }, []);

  const bumpTexture = useMemo(() => {
    const loader = new THREE.TextureLoader();
    return loader.load('/textures/earth-topology.png');
  }, []);

  const cloudsTexture = useMemo(() => {
    const canvas = document.createElement('canvas');
    canvas.width = 1024;
    canvas.height = 512;
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.fillStyle = 'rgba(255, 255, 255, 0.05)';
      for (let i = 0; i < 200; i++) {
        const x = Math.random() * canvas.width;
        const y = Math.random() * canvas.height;
        const r = Math.random() * 30 + 10;
        ctx.beginPath();
        ctx.arc(x, y, r, 0, Math.PI * 2);
        ctx.fill();
      }
    }
    const texture = new THREE.CanvasTexture(canvas);
    return texture;
  }, []);

  return (
    <group>
      <mesh>
        <sphereGeometry args={[1, 64, 64]} />
        <meshStandardMaterial
          map={earthTexture}
          bumpMap={bumpTexture}
          bumpScale={0.03}
          roughness={0.7}
          metalness={0.1}
        />
      </mesh>
      <mesh>
        <sphereGeometry args={[1.005, 64, 64]} />
        <meshStandardMaterial
          map={cloudsTexture}
          transparent
          opacity={0.15}
          depthWrite={false}
        />
      </mesh>
    </group>
  );
}

const CameraController = forwardRef((props, ref: any) => {
  return (
    <OrbitControls
      ref={ref}
      enablePan={true}
      enableZoom={true}
      enableRotate={true}
      minDistance={1.5}
      maxDistance={10}
      autoRotate
      autoRotateSpeed={0.3}
      enableDamping
      dampingFactor={0.05}
    />
  );
});

CameraController.displayName = 'CameraController';

function CameraAutoFit({ tracks, controlsRef }: { tracks: AnimalTrack[]; controlsRef: React.RefObject<any> }) {
  const { camera } = useThree();
  
  useEffect(() => {
    if (!controlsRef.current || tracks.length === 0) return;
    
    const controls = controlsRef.current;
    const allPoints: THREE.Vector3[] = [];
    
    tracks.forEach(track => {
      track.points.forEach(p => {
        allPoints.push(latLngToVector3(p.lat, p.lng));
      });
    });
    
    if (allPoints.length === 0) return;
    
    const box = new THREE.Box3().setFromPoints(allPoints);
    const center = box.getCenter(new THREE.Vector3());
    const size = box.getSize(new THREE.Vector3());
    const maxSize = Math.max(size.x, size.y, size.z);
    const radius = maxSize * 0.5;
    
    camera.position.copy(center.clone().add(new THREE.Vector3(0, radius * 0.3, radius * 2.5)));
    controls.target.copy(center);
    controls.update();
  }, [tracks, camera, controlsRef]);
  
  return null;
}

function LoadingFallback() {
  return (
    <mesh>
      <sphereGeometry args={[1, 32, 32]} />
      <meshBasicMaterial color="#001133" wireframe />
    </mesh>
  );
}

export default function Globe({ animalTracks, selectedAnimal, onAnimalSelect, playbackProgress }: GlobeProps) {
  const controlsRef = useRef<any>(null);
  
  useEffect(() => {
    if (!controlsRef.current || !selectedAnimal) return;
    
    const track = animalTracks.find(t => t.animalId === selectedAnimal);
    if (!track || track.points.length === 0) return;
    
    const currentIndex = Math.floor(track.points.length * playbackProgress) - 1;
    const point = track.points[Math.max(currentIndex, 0)];
    if (!point) return;
    
    const target = latLngToVector3(point.lat, point.lng);
    const controls = controlsRef.current;
    
    // Smooth camera animation
    const duration = 1000;
    const startPos = controls.object.position.clone();
    const startTarget = controls.target.clone();
    const offset = new THREE.Vector3(0.3, 0.2, 0.5).multiplyScalar(2);
    const newCameraPos = target.clone().add(offset);
    const startTime = Date.now();
    
    const animate = () => {
      const elapsed = Date.now() - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const eased = progress * (2 - progress);
      
      controls.object.position.lerp(startPos, newCameraPos, eased);
      controls.target.lerp(startTarget, target, eased);
      controls.update();
      
      if (progress < 1) {
        requestAnimationFrame(animate);
      }
    };
    
    animate();
  }, [selectedAnimal, playbackProgress, animalTracks]);
  
  return (
    <Canvas
      camera={{ position: [0, 0, 3], fov: 60 }}
      gl={{ antialias: true, alpha: true }}
      style={{ background: 'transparent' }}
    >
      <ambientLight intensity={0.15} />
      <pointLight position={[10, 10, 10]} intensity={1.2} color="#ffffff" />
      <pointLight position={[-10, -10, -5]} intensity={0.4} color="#0088ff" />
      <pointLight position={[5, -5, 10]} intensity={0.3} color="#00ff88" />

      <Stars radius={100} depth={50} count={3000} factor={4} saturation={0} fade speed={1} />

      <Suspense fallback={<LoadingFallback />}>
        <Earth />
      </Suspense>

      {animalTracks.map(track => (
        <AnimalPath
          key={track.animalId}
          track={track}
          progress={playbackProgress}
          onAnimalSelect={onAnimalSelect}
          isSelected={selectedAnimal === track.animalId}
        />
      ))}

      <CameraAutoFit tracks={animalTracks} controlsRef={controlsRef} />
      <CameraController ref={controlsRef} />

      <EffectComposer>
        <Bloom
          intensity={0.5}
          luminanceThreshold={0.2}
          luminanceSmoothing={0.9}
        />
      </EffectComposer>
    </Canvas>
  );
}
